#include<bits/stdc++.h>
using namespace std;
bool v[100066];
vector<int> e[100066];
struct node {
	int x, y, z;
};
int n;
int a[100005];
int aa;
node dfs(int x, int f) {

	node ans;
	ans.x = f;
	if (a[x] == 1) ans.y = x;
	else ans.z = x;
	v[x] = 1;
	for (int i = 0; i < e[x].size(); i++) {
		if (!v[e[x][i]]) {
			node temp = dfs(e[x][i], f + 1);
			if (temp.x > ans.x) {
				ans.x = temp.x;
				if (a[e[x][i]] == 0) ans.y = temp.y;
				else ans.z = temp.z;
			}
		}
	}
	v[x] = 0;
	return ans;
}
int dfs2(int x, int f) {
	int ans = f;
	v[x] = 1;
	for (int i = 0; i < e[x].size(); i++) {
		if (!v[e[x][i]]) {
			ans = max(ans, dfs2(e[x][i], f + 1));
		}
	}
	v[x] = 0;
	if (a[x] == 0) return ans;
	else return 0;
}
int dfs3(int x, int f) {
	int ans = f;
	v[x] = 1;
	for (int i = 0; i < e[x].size(); i++) {
		if (!v[e[x][i]]) {
			ans = max(ans, dfs2(e[x][i], f + 1));
		}
	}
	v[x] = 0;
	if (a[x] == 1) return ans;
	else return 0;
}
int main() {
	cin >> n;
	for (int i = 1; i <= n; i++) cin >> a[i];
	for (int i = 1; i < n; i++) {
		int x, y;
		cin >> x >> y;
		e[x].push_back(y);
		e[y].push_back(x);
	}
	aa = a[1];
	node ans = dfs(1, 0);
	cout<<max(dfs3(ans.y,0),dfs2(ans.z,0));
	return 0;
}
